import { request, authRequest } from "./api";
import { Course, UserProgress } from "../types/api.types";

export const coursesService = {
  // Получить все курсы
  async getAllCourses(): Promise<Course[]> {
    return request("/courses");
  },

  // Получить курс по ID
  async getCourseById(courseId: string): Promise<Course> {
    return request(`/courses/${courseId}`);
  },

  // Получить тренировки курса
  async getCourseWorkouts(courseId: string, token: string): Promise<any[]> {
    return authRequest(`/courses/${courseId}/workouts`, token);
  },

  // Добавить курс пользователю
  async addCourseToUser(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    return authRequest("/users/me/courses", token, {
      method: "POST",
      body: JSON.stringify({ courseId }),
    });
  },

  // Удалить курс у пользователя
  async removeCourseFromUser(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    return authRequest(`/users/me/courses/${courseId}`, token, {
      method: "DELETE",
    });
  },

  // Сбросить прогресс по курсу
  async resetCourseProgress(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    return authRequest(`/courses/${courseId}/reset`, token, {
      method: "PATCH",
    });
  },

  // Получить прогресс по курсу
  async getCourseProgress(
    courseId: string,
    token: string,
  ): Promise<UserProgress> {
    return authRequest(`/users/me/progress?courseId=${courseId}`, token);
  },
};
